import { useEffect, useRef, useState } from "react";
import { RefreshCw, X } from "lucide-react";
import { motion, AnimatePresence, useReducedMotion } from "framer-motion";
import { useServiceWorkerUpdate } from "@/lib/useServiceWorkerUpdate";
import { APP_VERSION } from "@/version";

const CHECK_INTERVAL_MS = 5 * 60 * 1000;
const DISMISS_KEY = "castia.updateDismissed";

export default function VersionPrompt() {
  const { needsUpdate: swNeedsUpdate, applyUpdate } = useServiceWorkerUpdate();
  const [stale, setStale] = useState(false);
  const [latest, setLatest] = useState(null);
  const [dismissed, setDismissed] = useState(false);
  const dismissedRef = useRef(false);
  const prefersReduced = useReducedMotion();

  // Check sessionStorage on mount so a dismissed update stays dismissed
  // for this session (per version).
  useEffect(() => {
    try {
      dismissedRef.current = sessionStorage.getItem(DISMISS_KEY) === APP_VERSION;
      if (dismissedRef.current) setDismissed(true);
    } catch { /* ignore */ }
  }, []);

  // Poll for stale version (non-PWA path).
  useEffect(() => {
    let cancelled = false;
    const check = async () => {
      try {
        const res = await fetch(`${process.env.PUBLIC_URL || ""}/version.json?_=${Date.now()}`, { cache: "no-store" });
        if (!res.ok) return;
        const j = await res.json();
        if (cancelled) return;
        setLatest(j.version || null);
        if (j.version && j.version !== APP_VERSION && !dismissedRef.current) {
          setStale(true);
        } else if (j.version === APP_VERSION) {
          setStale(false);
        }
      } catch { /* network error, ignore */ }
    };

    check();
    const t = setInterval(check, CHECK_INTERVAL_MS);
    return () => { cancelled = true; clearInterval(t); };
  }, []);

  // Priority: SW update is more authoritative — if both fire, show the SW one.
  const showUpdate = swNeedsUpdate && !dismissed;
  const showStale = stale && !swNeedsUpdate && !dismissed;

  const dismiss = () => {
    setDismissed(true);
    dismissedRef.current = true;
    try { sessionStorage.setItem(DISMISS_KEY, APP_VERSION); } catch { /* ignore */ }
  };

  const refresh = () => {
    window.location.reload();
  };

  if (!showUpdate && !showStale) return null;

  const isSW = showUpdate;
  const borderColor = isSW ? "border-emerald-500/30" : "border-amber-500/30";
  const bgAccent = isSW ? "bg-emerald-500/15 border-emerald-500/30" : "bg-amber-500/15 border-amber-500/30";
  const iconColor = isSW ? "text-emerald-400" : "text-amber-400";
  const btnColor = isSW
    ? "bg-emerald-500 hover:bg-emerald-400 text-black"
    : "bg-amber-500 hover:bg-amber-400 text-black";

  const content = (
    <div
      data-testid={isSW ? "update-prompt" : "stale-version-prompt"}
      role="status"
      className={`fixed bottom-4 left-4 right-4 z-[55] max-w-sm bg-bg-base/95 backdrop-blur-xl border ${borderColor} rounded-2xl p-3 shadow-2xl`}
    >
      <div className="flex items-center gap-3">
        <div className={`shrink-0 w-8 h-8 rounded-lg ${bgAccent} grid place-items-center`}>
          <RefreshCw className={`w-3.5 h-3.5 ${iconColor}`} />
        </div>
        <div className="flex-1 min-w-0">
          <div className="font-heading font-bold text-xs uppercase tracking-[0.18em] text-white">
            {isSW ? "Update available" : "Older version"}
          </div>
          <p className="text-zinc-400 text-[11px] leading-snug mt-0.5">
            {isSW
              ? "A new version of Castia is ready."
              : `You\u2019re on ${APP_VERSION}. Latest is ${latest}.`}
          </p>
        </div>
        <button
          data-testid={isSW ? "update-prompt-reload" : "stale-version-refresh"}
          onClick={isSW ? applyUpdate : refresh}
          className={`shrink-0 ${btnColor} font-bold uppercase tracking-[0.18em] text-[10px] px-3 py-1.5 rounded-sm transition-colors`}
        >
          {isSW ? "Reload" : "Refresh"}
        </button>
        <button
          onClick={dismiss}
          aria-label="Dismiss"
          className="shrink-0 text-zinc-500 hover:text-white transition-colors p-1"
        >
          <X className="w-3.5 h-3.5" />
        </button>
      </div>
    </div>
  );

  if (prefersReduced) return content;

  return (
    <AnimatePresence>
      <motion.div
        key={isSW ? "sw-update" : "stale-version"}
        initial={{ opacity: 0, y: 16 }}
        animate={{ opacity: 1, y: 0 }}
        exit={{ opacity: 0, y: 16 }}
        transition={{ duration: 0.3 }}
      >
        {content}
      </motion.div>
    </AnimatePresence>
  );
}
